  function patchStorageKeys(){ const originalGet=localStorage.getItem.bind(localStorage), originalSet=localStorage.setItem.bind(localStorage), originalRemove=localStorage.removeItem.bind(localStorage); localStorage.getItem=function(key){ if(LEGACY_BROWSER_SECRET_KEYS.has(String(key))) return 'server-managed'; return originalGet(key);}; localStorage.setItem=function(key,value){ if(LEGACY_BROWSER_SECRET_KEYS.has(String(key))) return; return originalSet(key,value);}; localStorage.removeItem=function(key){ if(LEGACY_BROWSER_SECRET_KEYS.has(String(key))) return; return originalRemove(key);}; }
  function hardenKeyInputs(){ document.querySelectorAll('input,textarea').forEach((el)=>{ const sig=[el.id,el.name,el.placeholder,el.className].join(' ').toLowerCase(); if(!/(api.?key|token|virtual.?key|openai|gemini|claude|anthropic|Server-managed AI lane|kaixu key|key for|bearer)/.test(sig)) return; try{ if(!el.value) el.value='server-managed'; el.placeholder='Server-managed by Skyes Over London'; el.readOnly=true; el.setAttribute('data-s0l26-key-hardened','1'); if(!el.nextElementSibling || !el.nextElementSibling.classList || !el.nextElementSibling.classList.contains('s0l26-key-note')){ const note=document.createElement('div'); note.className='s0l26-key-note'; note.textContent='Browser key entry disabled · kAIxU runs server-side only'; el.insertAdjacentElement('afterend', note);} }catch{} }); }
