  async function authFetch(path, options){ const headers=new Headers((options&&options.headers)||{}); if(state.token) headers.set('Authorization',`Bearer ${state.token}`); if(options&&options.body&&!headers.has('Content-Type')) headers.set('Content-Type','application/json'); const res=await fetch(path,{...(options||{}),headers,__s0l26_passthrough:true}); const text=await res.text(); let data={}; try{data=text?JSON.parse(text):{}}catch{data={raw:text}} if(!res.ok) throw new Error(data.error||text||`HTTP ${res.status}`); return data; }
  function serializePageState(){ const local={}; for(let i=0;i<localStorage.length;i++){ const key=localStorage.key(i); if(!key||LEGACY_BROWSER_SECRET_KEYS.has(key)) continue; const value=localStorage.getItem(key); if((value||'').length>120000) continue; local[key]=value; } const formState=[]; document.querySelectorAll('input,textarea,select').forEach((el)=>{ if(!el||el.type==='password'||el.hasAttribute('data-s0l26-key-hardened')||el.disabled) return; const key=el.id?`#${el.id}`:el.name?`[name="${CSS.escape(el.name)}"]`:''; if(!key) return; let value; if(el.type==='checkbox'||el.type==='radio') value=!!el.checked; else value=el.value; if(typeof value==='string'&&value.length>80000) return; formState.push({key,type:el.type||el.tagName.toLowerCase(),value}); }); return {title:document.title||appKey(),route:appKey(),href:location.href,saved_at:new Date().toISOString(),formState,localStorage:local,scroll:[window.scrollX||0,window.scrollY||0]}; }
  function applyPageState(data){ if(!data||typeof data!=='object') return; state.restoring=true; try{ Object.entries(data.localStorage||{}).forEach(([k,v])=>{ if(!LEGACY_BROWSER_SECRET_KEYS.has(k)) localStorage.setItem(k,v);}); (data.formState||[]).forEach((entry)=>{ const el=document.querySelector(entry.key); if(!el||el.hasAttribute('data-s0l26-key-hardened')) return; if(entry.type==='checkbox'||entry.type==='radio') el.checked=!!entry.value; else if(typeof entry.value!=='undefined') el.value=entry.value; try{ el.dispatchEvent(new Event('input',{bubbles:true})); }catch{} try{ el.dispatchEvent(new Event('change',{bubbles:true})); }catch{} }); if(Array.isArray(data.scroll)) setTimeout(()=>window.scrollTo(data.scroll[0]||0,data.scroll[1]||0),80); } finally{ state.restoring=false; } }
